logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
cloudwatch = boto3.client('cloudwatch')

SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', 'arn:aws:sns:us-east-1:123456789012:image-processing-notifications')
OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET', 'processed-images-bucket')

def lambda_handler(event, context):
    try:
        logger.info(f"Received event: {json.dumps(event)}")
        
        for record in event['Records']:
            bucket = record['s3']['bucket']['name']
            key = record['s3']['object']['key']
            
            logger.info(f"Processing image: {key} from bucket: {bucket}")
            
            image_data = s3_client.get_object(Bucket=bucket, Key=key)
            image_content = image_data['Body'].read()
            image_size = len(image_content)
            
            logger.info(f"Downloaded image {key}, size: {image_size} bytes")
            
            processed_result = process_image(image_content, key)
            
            output_key = f"processed/{datetime.now().strftime('%Y/%m/%d')}/{key.split('/')[-1]}"
            
            s3_client.put_object(
                Bucket=OUTPUT_BUCKET,
                Key=output_key,
                Body=json.dumps(processed_result),
                ContentType='application/json'
            )
            
            logger.info(f"Saved processing results to s3://{OUTPUT_BUCKET}/{output_key}")
            
            send_notification(key, processed_result)
            
            log_metrics(key, image_size, processed_result)
            
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Image processing completed successfully',
                'processed_count': len(event['Records'])
            })
        }
        
    except Exception as e:
        logger.error(f"Error processing image: {str(e)}", exc_info=True)
        
        send_error_notification(str(e))
        
        raise e

def process_image(image_content, filename):
    logger.info(f"Processing image: {filename}")
    
    result = {
        'filename': filename,
        'size_bytes': len(image_content),
        'processed_at': datetime.now().isoformat(),
        'status': 'success',
        'metadata': {
            'file_extension': filename.split('.')[-1] if '.' in filename else 'unknown',
            'processing_version': '1.0'
        }
    }
    
    logger.info(f"Image processing complete: {filename}")
    return result

def send_notification(image_key, processing_result):
    try:
        message = {
            'event_type': 'image_processed',
            'image_key': image_key,
            'timestamp': datetime.now().isoformat(),
            'result': processing_result
        }
        
        response = sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps(message),
            Subject=f'Image Processed: {image_key}',
            MessageAttributes={
                'event_type': {
                    'DataType': 'String',
                    'StringValue': 'image_processed'
                }
            }
        )
        
        logger.info(f"SNS notification sent: {response['MessageId']}")
        
    except Exception as e:
        logger.error(f"Error sending SNS notification: {str(e)}")

def send_error_notification(error_message):
    try:
        message = {
            'event_type': 'processing_error',
            'error': error_message,
            'timestamp': datetime.now().isoformat()
        }
        
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Message=json.dumps(message),
            Subject='Image Processing Error',
            MessageAttributes={
                'event_type': {
                    'DataType': 'String',
                    'StringValue': 'processing_error'
                }
            }
        )
        
    except Exception as e:
        logger.error(f"Error sending error notification: {str(e)}")

def log_metrics(image_key, image_size, processing_result):
    try:
        cloudwatch.put_metric_data(
            Namespace='ImageProcessing',
            MetricData=[
                {
                    'MetricName': 'ImageSize',
                    'Value': image_size,
                    'Unit': 'Bytes',
                    'Timestamp': datetime.now()
                },
                {
                    'MetricName': 'ImagesProcessed',
                    'Value': 1,
                    'Unit': 'Count',
                    'Timestamp': datetime.now()
                }
            ]
        )
        
        logger.info(f"Metrics logged to CloudWatch for {image_key}")
        
    except Exception as e:
        logger.error(f"Error logging metrics to CloudWatch: {str(e)}")